# On-demand retrieval: the model calls a tool that queries memory mid-run.
# This is useful when the model needs context it could not have known to
# request at the start — e.g. looking up past experience with a specific file.

RECALL_TOOL = {
    "name": "recall",
    "description": (
        "Look up information from long-term memory. "
        "Use this when you need to know what happened in past runs related to "
        "a specific file, module, or type of bug. "
        "Returns a list of relevant past findings as strings."
    ),
    "input_schema": {
        "type": "object",
        "properties": {
            "query": {
                "type": "string",
                "description": "What you want to recall. Free-text description.",
            },
            "top_k": {
                "type": "integer",
                "description": "Number of results to return. Defaults to 3.",
            },
        },
        "required": ["query"],
    },
}


def recall(query: str, top_k: int = 3, semantic_memory: SemanticMemory = None) -> str:
    """Tool implementation: query semantic memory and return results."""
    if semantic_memory is None:
        return "No semantic memory configured."
    results = semantic_memory.query(query, top_k=top_k)
    if not results:
        return "No relevant memory found."
    lines = [f"- {r['text']}" for r in results]
    return "\n".join(lines)

import pytest


class TestUpfrontRetrieval:
    def test_empty_memory_produces_plain_task(self):
        preamble = ""
        task = "Fix the bug."
        result = inject_before_task(preamble, task)
        assert result == "Fix the bug."

    def test_non_empty_preamble_prepended(self):
        preamble = "Previous run found: bug in auth.py."
        task = "Fix the bug."
        result = inject_before_task(preamble, task)
        assert "Previous run found" in result
        assert "Fix the bug" in result
        assert result.index("Previous run") < result.index("Fix the bug")


class TestTopKWithinBudget:
    def test_returns_as_many_as_fit(self):
        # Each result is 400 chars ≈ 100 tokens
        results = ["x" * 400] * 10
        selected = top_k_within_budget(results, max_tokens=250)
        assert len(selected) == 2   # 2 × 100 ≈ 200 tokens

    def test_returns_all_when_under_budget(self):
        results = ["short"] * 3
        selected = top_k_within_budget(results, max_tokens=1000)
        assert len(selected) == 3


class TestIsFresh:
    def test_recent_record_is_fresh(self):
        record = {"ts": time.time() - 10}
        assert is_fresh(record, max_age_seconds=60)

    def test_old_record_is_not_fresh(self):
        record = {"ts": time.time() - 7200}
        assert not is_fresh(record, max_age_seconds=3600)
